#include <OneWire.h>
#include <DallasTemperature.h>
#include <SD.h>
#define PH_PIN A0
#define ACID_VALVE 6
#define BASE_VALVE 5
#define STIRRER_PIN 8
#define OW_PIN 2
#define SD_CS 10
#define PH_SETPOINT 7.0f
#define DEADBAND 0.05f
#define PULSE_MS 200
#define FAULT_PH_LO 3.0f
#define FAULT_PH_HI 11.0f
OneWire ow(OW_PIN); DallasTemperature ds(&ow); File lg;
float ph_compensated_setpoint(float sp, float T){
  return sp - 0.003f*(T-25.0f);
}
void initHardware(){
  pinMode(ACID_VALVE,OUTPUT); pinMode(BASE_VALVE,OUTPUT); pinMode(STIRRER_PIN,OUTPUT);
  ds.begin(); SD.begin(SD_CS);
  lg=SD.open("ph.csv",FILE_WRITE);
  if(lg) lg.println("t_s,T_C,pH,sp,acid,base");
  digitalWrite(STIRRER_PIN,HIGH); Serial.begin(9600);
}
float readTemperatureSensor(){
  ds.requestTemperatures(); return ds.getTempCByIndex(0);
}
float readPhSensor(float T){
  float v=analogRead(PH_PIN)*5.0f/1023.0f;
  float pH_raw=7.0f+(2.5f-v)/0.18f;
  return pH_raw;
}
void dosingControl(float pH, float sp){
  if(pH>sp+DEADBAND){ digitalWrite(ACID_VALVE,HIGH); delay(PULSE_MS); digitalWrite(ACID_VALVE,LOW); }
  else if(pH<sp-DEADBAND){ digitalWrite(BASE_VALVE,HIGH); delay(PULSE_MS); digitalWrite(BASE_VALVE,LOW); }
}
void logDataSD(unsigned long t,float T,float pH,float sp,int acid,int base){
  if(lg){lg.print(t);lg.print(',');lg.print(T,2);lg.print(',');lg.print(pH,3);lg.print(',');lg.print(sp,3);lg.print(',');lg.print(acid);lg.print(',');lg.println(base);lg.flush();}
  Serial.print("T=");Serial.print(T,1);Serial.print(" pH=");Serial.println(pH,3);
}
void checkFaultSafety(float pH){
  if(pH<FAULT_PH_LO||pH>FAULT_PH_HI){
    digitalWrite(ACID_VALVE,LOW); digitalWrite(BASE_VALVE,LOW); digitalWrite(STIRRER_PIN,LOW);
    Serial.println("FAULT:pH_OOR"); if(lg)lg.println("FAULT:pH_OOR"); while(1);
  }
}
void setup(){ initHardware(); }
void loop(){
  static unsigned long prev=0; unsigned long now=millis();
  if(now-prev<2000) return; prev=now;
  float T=readTemperatureSensor();
  float pH=readPhSensor(T); checkFaultSafety(pH);
  float sp=ph_compensated_setpoint(PH_SETPOINT,T);
  int acid=(pH>sp+DEADBAND)?1:0, base=(pH<sp-DEADBAND)?1:0;
  dosingControl(pH,sp); logDataSD(now/1000,T,pH,sp,acid,base);
}
